using System;
using System.Linq;
using System.Reflection;
using Microsoft.VisualStudio.TestTools.UnitTesting;

var type = typeof(Assert);
var methods = type.GetMethods(BindingFlags.Public | BindingFlags.Static);
foreach (var m in methods.Where(m => m.Name is "AreEqual" or "AreNotEqual" or "AreSame" or "AreNotSame").OrderBy(m => m.Name))
{
    var parms = string.Join(", ", m.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"));
    var genArgs = m.IsGenericMethod ? $"<{string.Join(",", m.GetGenericArguments().Select(g => {
        var constraints = g.GetGenericParameterConstraints();
        var attrs = g.GenericParameterAttributes;
        var parts = new System.Collections.Generic.List<string>();
        if (constraints.Length > 0) parts.AddRange(constraints.Select(c => c.Name));
        if ((attrs & GenericParameterAttributes.ReferenceTypeConstraint) != 0) parts.Add("class");
        if ((attrs & GenericParameterAttributes.NotNullableValueTypeConstraint) != 0) parts.Add("struct");
        return parts.Count > 0 ? $"{g.Name} : {string.Join(", ", parts)}" : g.Name;
    }))}>": "";
    Console.WriteLine($"{m.Name}{genArgs}({parms})");
}
CSHARP
